633	func (pt *Path) setMappedLocations() {
634		if pt.mappedLocations != nil {
635			return
636		}
637	
638		mappedLocations := make(map[string]string)
639	
640		// predefined mapped locations, can be disabled
641		if pt.options.Bool(MappedLocationsEnabled, true) {
642			mappedLocations["hkcu:"] = pt.options.String(WindowsRegistryIcon, "\uF013")
643			mappedLocations["hklm:"] = pt.options.String(WindowsRegistryIcon, "\uF013")
644			mappedLocations[pt.normalize(pt.env.Home())] = pt.options.String(HomeIcon, "~")
645		}
646	
647		// merge custom locations with mapped locations
648		// mapped locations can override predefined locations
649		keyValues := pt.options.KeyValueMap(MappedLocations, make(map[string]string))
650		for key, value := range keyValues {
651			if key == "" {
652				continue
653			}
654	
655			location, err := template.Render(key, pt)
656			if err != nil {
657				log.Error(err)
658			}
659	
660			if location == "" {
661				continue
662			}
663	
664			if !strings.HasPrefix(location, regexPrefix) {
665				location = pt.normalize(location)
