803		}
804	
805		if pt.env.GOOS() == runtime.WINDOWS {
806			// Handle a UNC path, if any.
807			pattern := fmt.Sprintf(`^\%[1]s{2}(?P<hostname>[^\%[1]s]+)\%[1]s(?P<sharename>[^\%[1]s]+)(\%[1]s(?P<path>[\s\S]*))?$`, pt.pathSeparator)
