809			if len(matches) > 0 {
810				root = fmt.Sprintf(`%[1]s%[1]s%[2]s%[1]s%[3]s`, pt.pathSeparator, matches["hostname"], matches["sharename"])
811				relative = matches["path"]
812				return root, relative
813			}
814		}
815	
816		s := strings.SplitAfterN(inputPath, pt.pathSeparator, 2)
817		root = s[0]
818	
819		if len(s) == 2 {
820			if len(root) > 1 {
821				root = root[:len(root)-1]
822			}
823	
824			relative = s[1]
825		}
