// Trusted marks a template string as having been authored by the user in their
// own configuration (a segment/block/palette/etc. template field), as opposed
// to text assembled at runtime from external data (filesystem names, command
// output, API responses, ...). Only Trusted templates get the func map entries
// that touch the OS (cmd, readFile, stat, glob) or the environment (env,
// expandenv) — see RenderRestricted for anything that isn't.
//
// Converting a runtime-composed string to Trusted defeats this guarantee, so
// only do it where the string is read verbatim from a config field.
type Trusted string

type Text struct {
	context  Data
	template string
	trusted  bool
}

// New returns a Text instance from the pool with the given template and context
func get(template string, trusted bool, context any) *Text {
	if textPool == nil {
		// Fallback if pool is not initialized yet
		return &Text{context: context, template: template, trusted: trusted}
	}

	text := textPool.Get()
	text.template = template
	text.trusted = trusted
	text.context = context

	return text
}

// Render executes a template the user authored in their own configuration.
// The full func map is available, including cmd/readFile/stat/glob.
func Render(template Trusted, context any) (string, error) {
	return render(string(template), true, context)
}

// RenderRestricted executes a template that may contain (or be composed from)
// runtime data rather than user-authored config text. cmd/readFile/stat/glob
// and env/expandenv are not available.
func RenderRestricted(template string, context any) (string, error) {
	return render(template, false, context)
}

func render(template string, trusted bool, context any) (string, error) {
	t := get(template, trusted, context)
	defer t.release()

	if !strings.Contains(t.template, "{{") || !strings.Contains(t.template, "}}") {
		return t.template, nil
	}

	renderer := renderPool.Get()
	defer renderer.release()

	return renderer.execute(t)
}

// Release resets the Text instance and returns it to the pool
func (t *Text) release() {
	t.context = nil
	t.template = ""
	t.trusted = false

	if textPool != nil {
		textPool.Put(t)
	}
}

